external_apis.api:
POST /api/emergency-check
Input:  { symptoms: str, symptom_severity: float }
Output: { is_emergency: bool, confidence: float, reason: str }

POST /api/classify-urgency
Input:  { symptom_severity: float, symptom_count: int, duration: str,
          patient_age_risk: str, comorbidity_flag: bool }
Output: { urgency_score: float, label: "Self-care"|"Visit clinic"|"Emergency" }

POST /api/find-hospital
Input:  { user_location: str, urgency: str }
Output: { hospitals: [ { name: str, address: str, distance_km: float,
                          phone: str, open_now: bool } ] }
